const calculator = {
  BASE_COST: {
    studio: 100,
    '1br': 120,
    '2br': 150,
    '3br': 200,
    '4br+': 250
  },
  CLEANING_MULTIPLIER: {
    standard: 1,
    deep: 1.5,
    move_out: 1.75
  },
  FREQUENCY_MULTIPLIER: {
    one_time: 1,
    weekly: 0.8,
    biweekly: 0.85,
    monthly: 0.9
  },
  PET_SURCHARGE: 25,

  validate(inputs) {
    const errors = [];
    if (inputs === undefined || inputs === null) {
      return { error: "No input provided" };
    }

    // homeSize
    if (!inputs.homeSize) {
      errors.push("Missing homeSize");
    } else {
      const hs = String(inputs.homeSize).toLowerCase();
      if (!Object.keys(this.BASE_COST).includes(hs)) {
        errors.push("Invalid homeSize");
      }
    }

    // cleaningType
    if (!inputs.cleaningType) {
      errors.push("Missing cleaningType");
    } else {
      const ct = String(inputs.cleaningType).toLowerCase();
      if (!Object.keys(this.CLEANING_MULTIPLIER).includes(ct)) {
        errors.push("Invalid cleaningType");
      }
    }

    // frequency
    if (!inputs.frequency) {
      errors.push("Missing frequency");
    } else {
      const fq = String(inputs.frequency).toLowerCase();
      if (!Object.keys(this.FREQUENCY_MULTIPLIER).includes(fq)) {
        errors.push("Invalid frequency");
      }
    }

    // hasPets
    if (inputs.hasPets !== undefined) {
      if (typeof inputs.hasPets !== 'boolean') {
        errors.push("hasPets must be boolean");
      }
    } else {
      // if not provided, default to false? We treat as missing but we can set default, or error? TC14 shows missing all params, we only error on required ones. hasPets is optional maybe. But requirement says required, so we'll error if missing. However TC19 includes hasPets. The original parameters list says hasPets is checkbox. We'll require it. Add error if missing.
      errors.push("Missing hasPets");
    }

    if (errors.length > 0) {
      return { error: errors[0] }; // return first error
    }
    return { valid: true };
  },

  calculate(inputs) {
    // validation
    const validationResult = this.validate(inputs);
    if (validationResult.error) {
      return validationResult;
    }

    // normalize keys to lowercase
    const homeSize = String(inputs.homeSize).toLowerCase();
    const cleaningType = String(inputs.cleaningType).toLowerCase();
    const frequency = String(inputs.frequency).toLowerCase();
    const hasPets = inputs.hasPets;

    const base = this.BASE_COST[homeSize];
    const cleaningMultiplier = this.CLEANING_MULTIPLIER[cleaningType];
    const frequencyMultiplier = this.FREQUENCY_MULTIPLIER[frequency];
    const petSurcharge = hasPets ? this.PET_SURCHARGE : 0;

    const subtotal = base * cleaningMultiplier * frequencyMultiplier;
    const total = subtotal + petSurcharge;

    // round to cents
    const roundTotal = Math.round(total * 100) / 100;
    const roundSubtotal = Math.round(subtotal * 100) / 100;

    return {
      total: roundTotal,
      breakdown: {
        base: base,
        cleaningMultiplier: cleaningMultiplier,
        frequencyMultiplier: frequencyMultiplier,
        surcharges: petSurcharge,
        subtotal: roundSubtotal
      }
    };
  },

  formatCurrency(amount) {
    return '$' + amount.toFixed(2);
  }
};

const CALC_PARAMS = [
  {
    name: 'homeSize',
    label: 'Home Size',
    type: 'select',
    options: [
      ['studio', 'Studio'],
      ['1br', '1 Bedroom'],
      ['2br', '2 Bedrooms'],
      ['3br', '3 Bedrooms'],
      ['4br+', '4+ Bedrooms']
    ]
  },
  {
    name: 'cleaningType',
    label: 'Cleaning Type',
    type: 'select',
    options: [
      ['standard', 'Standard'],
      ['deep', 'Deep'],
      ['move_out', 'Move‑out']
    ]
  },
  {
    name: 'frequency',
    label: 'Frequency',
    type: 'select',
    options: [
      ['one_time', 'One‑time'],
      ['weekly', 'Weekly'],
      ['biweekly', 'Biweekly'],
      ['monthly', 'Monthly']
    ]
  },
  {
    name: 'hasPets',
    label: 'Have Pets?',
    type: 'checkbox'
  }
];

